import { readdir, readFile, stat, writeFile } from "node:fs/promises";
import { dirname, extname, join, relative } from "node:path";
import { fileURLToPath } from "node:url";
import prettier from "prettier";

const projectRoot = dirname(dirname(fileURLToPath(import.meta.url)));
const htmlBanner =
  "<!-- Generated by Next.js static export. Edit app/ source files and run npm run build:github. -->";
const jsBanner =
  "// Generated by Next.js static export. Do not edit. Edit app/ source files and run npm run build:github.";
const cssBanner =
  "/* Generated by Next.js static export. Do not edit. Edit app/ source files and run npm run build:github. */";
const exportRoots = ["index.html", "404.html", "404", "_not-found", "ls", "site"];
const assetRoots = ["_next/static/chunks"];

function isNextExportHtml(source) {
  return source.includes("__next_f") || source.includes("/_next/");
}

function normalizeGeneratedHtml(source) {
  let html = source.trim();

  if (!html.startsWith("<!-- Generated by Next.js")) {
    html = `${htmlBanner}\n${html}`;
  }

  html = html.replaceAll("charSet=", "charset=");

  html = html.replace(/<script>([\s\S]*?)<\/script>/g, (match, scriptBody) => {
    if (!scriptBody.includes("__next_f")) {
      return match;
    }

    if (scriptBody.includes("@ts-nocheck")) {
      return match;
    }

    return `<script>// @ts-nocheck\n${scriptBody}</script>`;
  });

  return html;
}

function normalizeGeneratedJs(source) {
  let js = source.trim();

  if (!js.startsWith("// Generated by Next.js")) {
    js = `${jsBanner}\n// @ts-nocheck\n${js}`;
  } else if (!js.includes("@ts-nocheck")) {
    js = js.replace(jsBanner, `${jsBanner}\n// @ts-nocheck`);
  }

  return js;
}

function normalizeGeneratedCss(source) {
  let css = source.trim();

  if (!css.startsWith("/* Generated by Next.js")) {
    css = `${cssBanner}\n${css}`;
  }

  return css;
}

async function collectFiles(targetPath, extensions) {
  const files = [];

  try {
    await stat(targetPath);
  } catch {
    return files;
  }

  async function walk(currentPath) {
    const stats = await stat(currentPath);

    if (stats.isFile()) {
      const extension = extname(currentPath);
      if (extensions.includes(extension)) {
        files.push(currentPath);
      }
      return;
    }

    const entries = await readdir(currentPath, { withFileTypes: true });
    for (const entry of entries) {
      await walk(join(currentPath, entry.name));
    }
  }

  await walk(targetPath);
  return files;
}

async function formatWithPrettier(source, parser) {
  return prettier.format(source, {
    parser,
    printWidth: 100,
    tabWidth: 2,
    useTabs: false,
    ...(parser === "html" ? { htmlWhitespaceSensitivity: "ignore" } : {})
  });
}

let formattedCount = 0;
let skippedCount = 0;

async function formatHtmlFiles() {
  const htmlFiles = (
    await Promise.all(exportRoots.map((target) => collectFiles(join(projectRoot, target), [".html"])))
  ).flat();

  for (const filePath of htmlFiles) {
    const source = await readFile(filePath, "utf8");

    if (!isNextExportHtml(source)) {
      skippedCount += 1;
      continue;
    }

    try {
      const formatted = await formatWithPrettier(normalizeGeneratedHtml(source), "html");
      await writeFile(filePath, formatted, "utf8");
      formattedCount += 1;
      console.log(`Formatted ${relative(projectRoot, filePath)}`);
    } catch (error) {
      skippedCount += 1;
      logSkip(filePath, error);
    }
  }
}

async function formatAssetFiles() {
  const assetFiles = (
    await Promise.all(
      assetRoots.map((target) => collectFiles(join(projectRoot, target), [".js", ".css"]))
    )
  ).flat();

  for (const filePath of assetFiles) {
    const source = await readFile(filePath, "utf8");
    const extension = extname(filePath);

    try {
      const normalized =
        extension === ".css" ? normalizeGeneratedCss(source) : normalizeGeneratedJs(source);
      const formatted = await formatWithPrettier(
        normalized,
        extension === ".css" ? "css" : "babel"
      );

      await writeFile(filePath, formatted, "utf8");
      formattedCount += 1;
      console.log(`Formatted ${relative(projectRoot, filePath)}`);
    } catch (error) {
      skippedCount += 1;
      logSkip(filePath, error);
    }
  }
}

function logSkip(filePath, error) {
  const message = error instanceof Error ? error.message.split("\n")[0] : String(error);
  console.warn(`Skipped ${relative(projectRoot, filePath)}: ${message}`);
}

await formatHtmlFiles();
await formatAssetFiles();

console.log(`Done. Formatted ${formattedCount} file(s), skipped ${skippedCount}.`);
